static const char *idle_string(time_t when) {
    static time_t now = 0;
    static char buf[22];
    time_t seconds_idle;
    if (now == 0)
        rpl_time(&now);
    seconds_idle = now - when;
    if (seconds_idle < 60)
        return "     ";
    if (seconds_idle < (24 * 60 * 60)) {
        int hours = seconds_idle / (60 * 60);
        int minutes = (seconds_idle % (60 * 60)) / 60;
        sprintf(buf, "%02d:%02d", hours, minutes);
    } else {
        intmax_t days = seconds_idle / (24 * 60 * 60);
        sprintf(buf, "%jdd", days);
    }
    return buf;
}

